#define AMB_TEMP 80.0f

static inline float compute_delta(__global const float *temp,
                                  __global const float *power,
                                  int row, int col, int r, int c,
                                  float Cap_1, float Rx_1, float Ry_1, float Rz_1)
{
    if ((r == 0) && (c == 0)) {
        return Cap_1 * (power[0] +
                        (temp[1] - temp[0]) * Rx_1 +
                        (temp[col] - temp[0]) * Ry_1 +
                        (AMB_TEMP - temp[0]) * Rz_1);
    } else if ((r == 0) && (c == col - 1)) {
        return Cap_1 * (power[c] +
                        (temp[c - 1] - temp[c]) * Rx_1 +
                        (temp[c + col] - temp[c]) * Ry_1 +
                        (AMB_TEMP - temp[c]) * Rz_1);
    } else if ((r == row - 1) && (c == col - 1)) {
        int idx = r * col + c;
        return Cap_1 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    } else if ((r == row - 1) && (c == 0)) {
        int idx = r * col;
        return Cap_1 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (temp[(r - 1) * col] - temp[idx]) * Ry_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    } else if (r == 0) {
        int idx = c;
        return Cap_1 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (temp[col + c] - temp[idx]) * Ry_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    } else if (c == col - 1) {
        int idx = r * col + c;
        return Cap_1 * (power[idx] +
                        (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    } else if (r == row - 1) {
        int idx = r * col + c;
        return Cap_1 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    } else if (c == 0) {
        int idx = r * col;
        return Cap_1 * (power[idx] +
                        (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    } else {
        int idx = r * col + c;
        return Cap_1 * (power[idx] +
                        (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (AMB_TEMP - temp[idx]) * Rz_1);
    }
}

__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      const int col,
                      const int row,
                      const int borderCols,
                      const int borderRows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    (void)borderCols;
    (void)borderRows;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) {
        return;
    }

    const float Cap_1 = (step / 1000.0f) / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    __global float *src = temp_src;
    __global float *dst = temp_dst;

    for (int it = 0; it < iteration; ++it) {
        for (int r = 0; r < row; ++r) {
            for (int c = 0; c < col; ++c) {
                int idx = r * col + c;
                float delta = compute_delta((__global const float *)src, power, row, col, r, c,
                                            Cap_1, Rx_1, Ry_1, Rz_1);
                dst[idx] = src[idx] + delta;
            }
        }

        __global float *tmp = src;
        src = dst;
        dst = tmp;
    }

    if ((iteration & 1) == 0) {
        int size = row * col;
        for (int i = 0; i < size; ++i) {
            temp_dst[i] = temp_src[i];
        }
    }
}
